 $crearUsuario=function(string $rol,string $sufijo)use($pdo,$tag,&$ids):int{$q=$pdo->prepare("INSERT INTO usuarios(nombre,apellido,correo,password,rol,estado,email_verificado) VALUES(:n,'Etapa4',:c,:p,:r,'activo',1)");$q->execute(['n'=>'Temporal '.$sufijo,'c'=>$tag.$sufijo.'@example.invalid','p'=>password_hash(bin2hex(random_bytes(16)),PASSWORD_DEFAULT),'r'=>$rol]);$id=(int)$pdo->lastInsertId();$ids['usuarios'][]=$id;return$id;};
