 $crearContenido=function(string $tipo,string $titulo,float $peso)use($pdo,$cap,$seccion,$docente,&$ids):int{$q=$pdo->prepare("INSERT INTO contenidos(asignatura_id,seccion_id,docente_id,modulo,tipo,titulo,descripcion,estado,activo,obligatorio,peso_progreso,fecha_publicacion) VALUES(:a,:s,:d,'Unidad 1',:t,:n,'Contenido temporal','activo',1,1,:p,NOW())");$q->execute(['a'=>$cap,'s'=>$seccion,'d'=>$docente,'t'=>$tipo,'n'=>$titulo,'p'=>$peso]);$id=(int)$pdo->lastInsertId();$ids['contenidos'][]=$id;return$id;};
 $texto=$crearContenido('texto','Lectura obligatoria',40);$actividad=$crearContenido('actividad','Actividad obligatoria',60);
