 $p=progresoInscripcion($pdo,$ins);$assert($p['porcentaje']===0.0,'Abrir o existir contenido no lo marca como completado');
 $pdo->prepare('INSERT INTO progreso_contenido(inscripcion_id,contenido_id,visto_at,ultima_actividad_at) VALUES(:i,:c,NOW(),NOW())')->execute(['i'=>$ins,'c'=>$texto]);$p=progresoInscripcion($pdo,$ins);$assert($p['porcentaje']===0.0&&$p['contenidos_vistos']===1,'Visualizar registra actividad pero no aumenta el progreso');
 $pdo->prepare('UPDATE progreso_contenido SET completado_at=NOW() WHERE inscripcion_id=:i AND contenido_id=:c')->execute(['i'=>$ins,'c'=>$texto]);$p=progresoInscripcion($pdo,$ins);$assert($p['porcentaje']===40.0,'Completar explícitamente un contenido informativo aplica su peso');
 $q=$pdo->prepare("INSERT INTO entregas_contenido(contenido_id,estudiante_id,asignatura_id,seccion_id,intento,comentario,estado) VALUES(:c,:u,:a,:s,1,'Primera entrega','rechazada')");$q->execute(['c'=>$actividad,'u'=>$estudiante,'a'=>$cap,'s'=>$seccion]);$entrega1=(int)$pdo->lastInsertId();$ids['entregas'][]=$entrega1;$p=progresoInscripcion($pdo,$ins);$assert(!$p['elegible']&&$p['entregas_rechazadas']===1,'Una actividad obligatoria rechazada bloquea el certificado');
 foreach([-0.01,10.01] as$invalida){$bloqueada=false;try{$pdo->prepare('UPDATE entregas_contenido SET nota=:n WHERE id=:i')->execute(['n'=>$invalida,'i'=>$entrega1]);}catch(PDOException){$bloqueada=true;}$assert($bloqueada,'MySQL rechaza la nota fuera de rango '.$invalida);}
 $q=$pdo->prepare("INSERT INTO entregas_contenido(contenido_id,estudiante_id,asignatura_id,seccion_id,intento,comentario,estado,nota,retroalimentacion,revisado_at,revisado_por) VALUES(:c,:u,:a,:s,2,'Corrección','aprobada',8.75,'Cumple los criterios',NOW(),:d)");$q->execute(['c'=>$actividad,'u'=>$estudiante,'a'=>$cap,'s'=>$seccion,'d'=>$docente]);$entrega2=(int)$pdo->lastInsertId();$ids['entregas'][]=$entrega2;
 $pdo->prepare("INSERT INTO entrega_revisiones(entrega_id,docente_id,estado_anterior,estado_nuevo,nota_nueva,retroalimentacion) VALUES(:e,:d,'enviada','aprobada',8.75,'Cumple los criterios')")->execute(['e'=>$entrega2,'d'=>$docente]);
 $p=progresoInscripcion($pdo,$ins);$assert($p['porcentaje']===100.0&&$p['elegible']&&$p['promedio']===8.75,'La entrega aprobada completa el progreso individual y calcula promedio');
 $cert1=generarCertificadoInscripcion($pdo,$ins,$docente);$cert2=generarCertificadoInscripcion($pdo,$ins,$docente);$assert((int)$cert1['id']===(int)$cert2['id'],'La emisión repetida es idempotente y no duplica certificados');$q=$pdo->prepare('SELECT COUNT(*) FROM certificados_capacitacion WHERE inscripcion_id=:i');$q->execute(['i'=>$ins]);$assert((int)$q->fetchColumn()===1,'Existe un único certificado por inscripción');$pdf=rutaPrivadaAcademica($cert1['pdf_relpath']);$assert($pdf!==null&&str_starts_with((string)file_get_contents($pdf,false,null,0,4),'%PDF'),'El certificado se genera como PDF privado usando la plantilla oficial');
 $assert(rutaPrivadaAcademica('../.env')===null,'El resolvedor privado bloquea traversal de rutas');$assert(urlVideoAcademicoValida('https://www.youtube.com/watch?v=abc')&&!urlVideoAcademicoValida('https://example.com/video.mp4'),'Los enlaces de video se limitan a proveedores autorizados');
 echo 'OK '.count($ok)." pruebas\n";foreach($ok as$m)echo '- '.$m."\n";
}finally{
 try{$pdo->beginTransaction();if(isset($ids['ins'])){$pdo->prepare('DELETE FROM admin_notices WHERE user_id IN (SELECT id FROM usuarios WHERE correo LIKE :c)')->execute(['c'=>$tag.'%@example.invalid']);$pdo->prepare('DELETE FROM certificados_capacitacion WHERE inscripcion_id=:i')->execute(['i'=>$ids['ins']]);$pdo->prepare('DELETE FROM entrega_revisiones WHERE entrega_id IN (SELECT id FROM entregas_contenido WHERE asignatura_id=:a)')->execute(['a'=>$ids['cap']]);$pdo->prepare('DELETE FROM entrega_evidencias WHERE entrega_id IN (SELECT id FROM entregas_contenido WHERE asignatura_id=:a)')->execute(['a'=>$ids['cap']]);$pdo->prepare('DELETE FROM entregas_contenido WHERE asignatura_id=:a')->execute(['a'=>$ids['cap']]);$pdo->prepare('DELETE FROM progreso_contenido WHERE inscripcion_id=:i')->execute(['i'=>$ids['ins']]);$pdo->prepare('DELETE FROM contenidos WHERE asignatura_id=:a')->execute(['a'=>$ids['cap']]);$pdo->prepare('DELETE FROM inscripciones_capacitacion WHERE id=:i')->execute(['i'=>$ids['ins']]);}$pdo->prepare('DELETE FROM capacitacion_secciones WHERE asignatura_id=:a')->execute(['a'=>$ids['cap']]);$pdo->prepare('DELETE FROM capacitacion_pagos WHERE asignatura_id=:a')->execute(['a'=>$ids['cap']]);$pdo->prepare('DELETE FROM docentes_asignaturas WHERE asignatura_id=:a')->execute(['a'=>$ids['cap']]);$pdo->prepare('DELETE FROM asignaturas WHERE id=:a')->execute(['a'=>$ids['cap']]);if(!empty($ids['usuarios'])){$marks=implode(',',array_fill(0,count($ids['usuarios']),'?'));$pdo->prepare("DELETE FROM usuarios WHERE id IN($marks)")->execute($ids['usuarios']);}$pdo->commit();if($pdf&&is_file($pdf))unlink($pdf);}catch(Throwable$cleanup){if($pdo->inTransaction())$pdo->rollBack();fwrite(STDERR,'Limpieza: '.$cleanup->getMessage()."\n");}
